  Serial.print(F("i2s install 1\n"));
  es8311_set_voice_volume(45);
  Serial.print(F("i2s install 2\n"));
  es8311_set_mic_gain(ES8311_MIC_GAIN_12DB);

  i2s_install();
  Serial.print(F("i2s install \n"));
  Serial.print(F("Set pin ok\n"));
